SELECT m.meetingId, m.title, m.placeName, m.meetingDate, m.startTime, m.maxMembers, m.status, m.thumbnailImage, m.content, s.name as sportName, CONCAT(r.sido, " ", r.sigungu, " ", COALESCE(r.dong, "")) as regionName, (SELECT nickname FROM users WHERE userId = m.hostUserId) as meetingHostName, (SELECT COUNT(*) FROM meetingParticipants mp WHERE mp.meetingId = m.meetingId AND mp.status="APPROVED") as approvedCount, CASE WHEN m.status = 'RECRUITING' THEN '모집중' ELSE m.status END as statusText FROM meetings m JOIN sports s ON m.sportId = s.sportId JOIN regions r ON m.regionId = r.regionId WHERE m.deletedAt IS NULL AND m.status = 'RECRUITING'
AND s.category = #{category}
ORDER BY m.createdAt DESC LIMIT #{limit} OFFSET #{offset}

SELECT m.meetingId, m.title, m.placeName, m.meetingDate, m.startTime, m.maxMembers, m.status, m.thumbnailImage, s.name as sportName, CONCAT(r.sido, " ", r.sigungu, " ", COALESCE(r.dong, "")) as regionName, (SELECT nickname FROM users WHERE userId = m.hostUserId) as meetingHostName, (SELECT COUNT(*) FROM meetingParticipants mp WHERE mp.meetingId = m.meetingId AND mp.status="APPROVED") as approvedCount FROM meetings m JOIN sports s ON m.sportId = s.sportId JOIN regions r ON m.regionId = r.regionId WHERE m.deletedAt IS NULL AND m.status = 'RECRUITING' AND m.meetingId IN
#{meetingId}
ORDER BY m.createdAt DESC

SELECT m.meetingId as meetingId, m.title, m.placeName as placeName, m.meetingDate as meetingDate, m.startTime as startTime, m.maxMembers as maxMembers, m.status, m.content, m.address, m.thumbnailImage as thumbnailImage, s.name sportName, CONCAT(r.sido," ",r.sigungu," ",COALESCE(r.dong,"")) regionName, ( SELECT nickname FROM users where userId = m.hostUserId ) meetingHostName, ( SELECT profileImage FROM users where userId = m.hostUserId ) hostProfileImage, ( SELECT COUNT(*) FROM meetingParticipants mp WHERE mp.meetingId = m.meetingId AND mp.status="APPROVED" ) + CASE WHEN EXISTS ( SELECT 1 FROM meetingParticipants hostMp WHERE hostMp.meetingId = m.meetingId AND hostMp.userId = m.hostUserId AND hostMp.status = "APPROVED" ) THEN 0 ELSE 1 END AS approvedCount FROM meetings m JOIN sports s ON m.sportId = s.sportId JOIN regions r ON m.regionId = r.regionId WHERE m.deletedAt IS NULL
AND m.sportId = #{sportId}
AND s.name = #{sportName}
AND m.meetingDate = #{meetingDate}
AND m.regionId = #{regionId}
AND r.sido = #{sido} AND r.sigungu = #{sigungu} AND r.dong = #{dong}
AND r.sido = #{sido} AND r.sigungu = #{sigungu}
AND r.sido = #{sido}
AND r.sido = (SELECT br.sido FROM regions br WHERE br.regionId = #{baseRegionId}) AND r.sigungu = (SELECT br.sigungu FROM regions br WHERE br.regionId = #{baseRegionId})
AND m.status = #{status}
AND ( m.title LIKE CONCAT('%', #{keyword}, '%') OR m.content LIKE CONCAT('%', #{keyword}, '%') OR m.placeName LIKE CONCAT('%', #{keyword}, '%') OR m.address LIKE CONCAT('%', #{keyword}, '%')
OR s.name LIKE CONCAT('%', #{keyword}, '%')
OR r.sido LIKE CONCAT('%', #{keyword}, '%') OR r.sigungu LIKE CONCAT('%', #{keyword}, '%') OR r.dong LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY CASE WHEN #{baseRegionId} IS NOT NULL AND m.regionId = #{baseRegionId} THEN 0 ELSE 1 END, CASE m.status WHEN 'RECRUITING' THEN 0 WHEN 'CLOSED' THEN 1 WHEN 'ONGOING' THEN 2 WHEN 'COMPLETED' THEN 3 WHEN 'CANCELLED' THEN 4 ELSE 5 END, m.meetingDate ASC, m.startTime ASC, m.createdAt DESC LIMIT #{size} OFFSET #{offset}

